#!/usr/bin/env bash
# Regenerate per-(traceloop x python) lock files from .github/release-config.json.
# Each lock is a full `pip freeze` of (requirements.in + traceloop-sdk==<T>)
# resolved inside python:<X.Y>-slim on linux/amd64, matching the image build.
# AUTO-GENERATED lock files — do not hand-edit. Run: make lock
set -euo pipefail

HERE="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"   # python-instrumentation-provider/
CONFIG="$HERE/../.github/release-config.json"
LOCK_DIR="$HERE/locks"
REQ_IN="$HERE/requirements.in"

command -v jq >/dev/null || { echo "jq is required" >&2; exit 1; }
command -v docker >/dev/null || { echo "docker is required" >&2; exit 1; }
[ -f "$CONFIG" ] || { echo "release-config.json not found at $CONFIG" >&2; exit 1; }
[ -f "$REQ_IN" ] || { echo "requirements.in not found at $REQ_IN" >&2; exit 1; }

mkdir -p "$LOCK_DIR"

# Unique (traceloop_version, python_version) pairs across all AMP versions.
pairs="$(jq -r '.["python-instrumentation-provider"][]
  | .traceloop_version as $t
  | .python_versions[]
  | "\($t) \(.)"' "$CONFIG" | sort -u)"

while read -r T PY; do
  [ -z "${T:-}" ] && continue
  out="$LOCK_DIR/traceloop-${T}-python${PY}.txt"
  echo "Locking traceloop-sdk==$T on python$PY -> ${out#"$HERE"/}"
  freeze="$(docker run --rm --platform linux/amd64 \
    -v "$REQ_IN:/tmp/requirements.in:ro" \
    "python:${PY}-slim" \
    sh -c "pip install --no-cache-dir -q -r /tmp/requirements.in 'traceloop-sdk==${T}' --target /tmp/p >/dev/null 2>&1 && pip list --path /tmp/p --format=freeze | sort")"
  {
    echo "# AUTO-GENERATED by 'make lock' from .github/release-config.json — DO NOT EDIT."
    echo "# Inputs: requirements.in + traceloop-sdk==${T}   (python ${PY}, linux/amd64)"
    echo "$freeze"
  } > "$out"
done <<< "$pairs"

echo "Done. Wrote locks to ${LOCK_DIR#"$HERE"/}/"
